- Western Europe is a region known for high standards of living and social well-being.
- Happiness score is a measure of how happy citizens of a country are; 
- GDP per capita is a measure of a country's economic output divided by its population; 
- Life expectancy is the average number of years a person from a particular country is expected to live.

sql:
SELECT c.country_name
FROM countries c
JOIN happiness_data h ON c.country_id = h.country_id
WHERE h.happiness_score = (
    SELECT MAX(happiness_score) FROM happiness_data
);

SELECT AVG(happiness_score) AS average_happiness_score
FROM happiness_data
WHERE year = 2022;

SELECT country_id, freedom_score, year
FROM freedom_data
WHERE year = 2022;

SELECT country_id, family_support
FROM social_data
WHERE year = 2022;
